    ["Statusbar texture used for the absorb overlay. Stripes or patterned textures make absorbs easier to read at a glance."] = "흡수 오버레이에 사용하는 상태바 텍스처입니다. 줄무늬나 패턴 텍스처는 흡수를 한눈에 읽기 쉽게 합니다.",
    ["Statusbar texture used for the bar fill."] = "바 채움에 사용하는 상태바 텍스처입니다.",
    ["Statusbar texture used for the health bar. Supports SharedMedia textures."] = "체력 바에 사용하는 상태바 텍스처입니다. SharedMedia 텍스처를 지원합니다.",
    ["Statusbar texture used for the health bar. Supports SharedMedia."] = "체력 바에 사용하는 상태바 텍스처입니다. SharedMedia를 지원합니다.",
    ["Statusbar texture used for the power fill."] = "파워 채움에 사용하는 상태바 텍스처입니다.",
    ["Statusbar texture used to fill the castbar. Supports SharedMedia."] = "캐스트바를 채우는 상태바 텍스처입니다. SharedMedia를 지원합니다.",
    ["Stop the combat-end profiler and unwrap functions."] = "전투 종료 프로파일러를 중지하고 함수를 원래대로 되돌립니다.",
    ["Store separate entry lists per specialization, so each spec shows a different set of tracked spells. The current list is swapped in on spec change."] = "특성별로 별도 항목 목록을 저장해 각 특성이 다른 추적 주문 세트를 보이게 합니다. 특성 변경 시 현재 목록이 교체됩니다.",
    ["Store text settings separately per specialization."] = "텍스트 설정을 특성별로 따로 저장합니다.",
    ["Store whispers"] = "귓속말 저장",
    ["Stored but not joined"] = "저장됨, 하지만 가입하지 않음",
    ["Stored exclusion for '%s'. Disable to remove from the persistent exclusion set."] = "'%s'에 대한 저장된 제외 항목입니다. 비활성화하면 영구 제외 집합에서 제거됩니다.",
    ["Strength"] = "힘",
    ["Stretch bars to match the width of the frame they anchor to (e.g. the player frame)."] = "앵커가 붙은 프레임의 너비에 맞게 바를 늘립니다(예: 플레이어 프레임).",
    ["Stretch the bar to match the frame size."] = "프레임 크기에 맞게 바를 늘립니다.",
    ["Strip the guild name line from player tooltips."] = "플레이어 툴팁에서 길드 이름 줄을 제거합니다.",
    ["Strip the realm name from cross-realm player tooltips for a cleaner display."] = "더 깔끔한 표시를 위해 교차 서버 플레이어 툴팁에서 지역 이름을 제거합니다.",
    ["Stroke style of the ring that surrounds the reticle."] = "조준선을 둘러싼 링의 스트로크 스타일입니다.",
    ["Subsystems"] = "하위 시스템",
    ["Subtle Pulse"] = "은은한 펄스",
    ["Summon Pending"] = "소환 대기 중",
    ["Support"] = "지원",
    ["Supports SharedMedia textures. Install the SharedMedia addon to add your own."] = "SharedMedia 텍스처를 지원합니다. 자신만의 미디어를 추가하려면 SharedMedia 애드온을 설치하세요.",
    ["Suppress all cooldown effects (swipe, overlay, flash) for this container, even on Blizzard-managed elements driven by the same icons."] = "이 컨테이너의 모든 재사용 대기 효과(스와이프, 오버레이, 플래시)를 같은 아이콘으로 구동되는 Blizzard 관리 요소까지도 모두 억제합니다.",
    ["Suppress all tooltips while you're in combat. Use the modifier key below to force-show them when needed."] = "전투 중 모든 툴팁을 억제합니다. 필요할 때 아래 수정 키로 강제 표시할 수 있습니다.",
    ["Suppress entitlement and recruit-a-friend delivery toast notifications."] = "계정 권한 및 친구 초대 보상 알림을 억제합니다.",
    ["Suppress general event toast popups, often triggered by campaign progress or housing updates."] = "캠페인 진행이나 주거 업데이트로 자주 발생하는 일반 이벤트 토스트 팝업을 억제합니다.",
    ["Suppress the blocking static popups that appear for housing-related confirmations."] = "주거 관련 확인에 나타나는 차단형 정적 팝업을 억제합니다.",
    ["Suppress the blocking static popups that appear for talent-related confirmations."] = "특성 관련 확인에 나타나는 차단형 정적 팝업을 억제합니다.",
    ["Suppress the glow animation on every microbutton (collections, achievements, etc.) when new items are detected."] = "새 항목이 감지되면 모든 마이크로 버튼(수집, 업적 등)의 광택 애니메이션을 억제합니다.",
    ["Suppress the pulsing reminder on the talent microbutton that appears when unspent points are available."] = "사용하지 않은 특성 포인트가 있을 때 나타나는 특성 마이크로 버튼의 깜박임 알림을 억제합니다.",
    ["Suppress the red error messages printed above the action bar, such as Not Enough Mana or Spell Not Ready."] = "Not Enough Mana, Spell Not Ready 같은 액션 바 위 빨간 오류 메시지를 억제합니다.",
    ["Suppress the toast that pops when you acquire a new cosmetic item."] = "새 꾸미기 아이템을 획득했을 때 뜨는 토스트를 억제합니다.",
    ["Suppress the toast that pops when you learn a new battle pet."] = "새 애완동물을 배울 때 뜨는 토스트를 억제합니다.",
    ["Suppress the toast that pops when you learn a new mount."] = "새 탈것을 배울 때 뜨는 토스트를 억제합니다.",
    ["Suppress the toast that pops when you learn a new toy."] = "새 장난감을 배울 때 뜨는 토스트를 억제합니다.",
    ["Suppress the tutorial help tip callouts that Blizzard shows near talent and spellbook buttons."] = "Blizzard가 특성 및 주문책 버튼 근처에 띄우는 튜토리얼 도움말 호출을 억제합니다.",
    ["Suppress the yellow info messages printed above the action bar, such as quest objective progress updates."] = "퀘스트 목표 진행 업데이트 같은 액션 바 위 노란 정보 메시지를 억제합니다.",
    ["Suppress warband scene notification toasts."] = "워밴드 장면 알림 토스트를 억제합니다.",
    ["Swap the vigor bar color while Thrill of the Skies is active so the buff state is obvious."] = "Thrill of the Skies 활성 중에는 vigor 바 색상을 바꿔 버프 상태가 분명히 보이게 합니다.",
    ["Swap to Primary Position"] = "기본 위치로 전환",
    ["Sweep the GCD during instant melee swings, not just during spell casts."] = "주문 시전뿐 아니라 즉시 근접 스윙 중에도 GCD를 스윕합니다.",
    ["Swipe Custom Color"] = "스와이프 사용자 지정 색상",
    ["Switch Loadout"] = "장비 모음 전환",
    ["Switch Loadout (TLM)"] = "장비 모음 전환 (TLM)",
    ["Switch Profile"] = "프로필 전환",
    ["Switch Specialization"] = "전문화 전환",
    ["Switch between Party and Raid frame settings. Spotlight is only available for Raid frames."] = "파티와 레이드 프레임 설정을 전환합니다. 스포트라이트는 레이드 프레임에서만 사용할 수 있습니다.",
    ["Switch to a different profile. Entries tagged (Preset) are installed from QUI's bundled presets on first pick."] = "다른 프로필로 전환합니다. (Preset) 태그가 붙은 항목은 첫 선택 시 QUI 번들 프리셋에서 설치됩니다.",
    ["Switch to per-spec default chat tabs instead of a single default. Each spec gets its own dropdown above."] = "단일 기본값 대신 특성별 기본 채팅 탭으로 전환합니다. 각 특성은 위 드롭다운을 따로 사용합니다.",
